const p = msg.payload || {};
const up = p.uplink_message || {};
const decoded = up.decoded_payload || {};
const dev = (p.end_device_ids && p.end_device_ids.device_id) || "unknown";

// every numeric decoded field becomes an Influx field
const fields = {};
for (const k in decoded) {
    if (typeof decoded[k] === "number") fields[k] = decoded[k];
}

// link quality from the first gateway
const rx = (up.rx_metadata && up.rx_metadata[0]) || {};
if (typeof rx.rssi === "number") fields.rssi = rx.rssi;
if (typeof rx.snr === "number") fields.snr = rx.snr;

if (Object.keys(fields).length === 0) { return null; }

// influxdb 'out' node (v2): payload = [ fields, tags ]
msg.payload = [ fields, { device: dev } ];
return msg;
